import React, { useState, useEffect } from "react";
import "../styles/GeneralChat.css";

const emotionMap = {
  tired: "😴 Exhausted",
  exhausted: "😴 Exhausted",
  sad: "😔 Sad",
  lonely: "💙 Lonely",
  stressed: "😣 Stressed",
  happy: "😊 Calm",
  anxious: "😟 Anxious",
};

const responses = [
  {
    keywords: ["hello", "hi", "hey"],
    reply: "Hi 🌱 I’m here with you. How are you feeling today?",
  },
  {
    keywords: ["tired", "exhausted", "draining"],
    reply:
      "That sounds really exhausting 💜 You’ve been carrying a lot. Do you want to talk about what’s draining you?",
  },
  {
    keywords: ["song", "music"],
    reply:
      "Here are some gentle songs that help when you feel exhausted 🎧\n\n• Fix You – Coldplay\n• Weightless – Marconi Union\n• Let Her Go – Passenger\n\nWould you like something calming or uplifting?",
  },
  {
    keywords: ["yes"],
    reply: "I’m listening 💜 Take your time. What’s been on your mind?",
  },
];

function detectEmotion(text) {
  const lower = text.toLowerCase();
  for (let key in emotionMap) {
    if (lower.includes(key)) return emotionMap[key];
  }
  return "🧠 Listening";
}

function getReply(text) {
  const lower = text.toLowerCase();
  for (let item of responses) {
    if (item.keywords.some(k => lower.includes(k))) {
      return item.reply;
    }
  }
  return "I hear you 💜 Tell me more about what you’re feeling.";
}

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text:
        "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
      emotion: "🧠 Listening",
    },
  ]);

  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);

  const sendMessage = () => {
    if (!input.trim()) return;

    const emotion = detectEmotion(input);

    const userMsg = {
      sender: "user",
      text: input,
      emotion,
    };

    setMessages(prev => [...prev, userMsg]);
    setInput("");
    setTyping(true);

    setTimeout(() => {
      const botMsg = {
        sender: "bot",
        text: getReply(input),
        emotion: "💜 Support",
      };
      setMessages(prev => [...prev, botMsg]);
      setTyping(false);
    }, 1200); // typing animation delay
  };

  return (
    <div className="chat-page">
      <h2 className="chat-title">General Chat</h2>

      <div className="chat-card">
        {messages.map((msg, i) => (
          <div key={i} className={`msg ${msg.sender}`}>
            <div className="emotion-tag">{msg.emotion}</div>
            <p>{msg.text}</p>
          </div>
        ))}

        {typing && (
          <div className="msg bot typing">
            <span></span>
            <span></span>
            <span></span>
          </div>
        )}
      </div>

      <div className="input-area">
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="Type how you feel..."
          onKeyDown={e => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
